const fs = require('fs');
const path = require('path');
const memDir = '/outputs/memory-short-term';
if (!fs.existsSync(memDir)) {
  return [{ json: { memories: [], count: 0 } }];
}
const files = fs.readdirSync(memDir).filter(f => f.endsWith('.json'));
const memories = files.map(f => {
  try { return JSON.parse(fs.readFileSync(path.join(memDir, f), 'utf-8')); }
  catch(e) { return null; }
}).filter(Boolean);
return [{ json: { memories, count: memories.length } }];

const fs = require('fs');
const content = ($json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) || '{}';
const outDir = '/outputs/memory-consolidated';
fs.mkdirSync(outDir, { recursive: true });
const fname = outDir + '/consolidation-' + new Date().toISOString().split('T')[0] + '.json';
fs.writeFileSync(fname, content);
return [{ json: { saved: fname } }];
